#include "XSbench_header.cuh"
#include <string.h>
#include <strings.h>

SimulationData grid_init_do_not_profile( Inputs in, int mype )
{
	SimulationData SD = {};

	size_t nbytes = 0;
	uint64_t seed = 42;

	if(mype == 0) printf("Intializing nuclide grids...\n");

	SD.length_nuclide_grid = in.n_isotopes * in.n_gridpoints;
	SD.nuclide_grid = (NuclideGridPoint *) malloc( SD.length_nuclide_grid * sizeof(NuclideGridPoint));
	assert(SD.nuclide_grid != NULL);
	nbytes += (size_t) SD.length_nuclide_grid * sizeof(NuclideGridPoint);

	for( int i = 0; i < SD.length_nuclide_grid; i++ )
	{
		SD.nuclide_grid[i].energy        = LCG_random_double(&seed);
		SD.nuclide_grid[i].total_xs      = LCG_random_double(&seed);
		SD.nuclide_grid[i].elastic_xs    = LCG_random_double(&seed);
		SD.nuclide_grid[i].absorbtion_xs = LCG_random_double(&seed);
		SD.nuclide_grid[i].fission_xs    = LCG_random_double(&seed);
		SD.nuclide_grid[i].nu_fission_xs = LCG_random_double(&seed);
	}

	for( int i = 0; i < in.n_isotopes; i++ )
		qsort( &SD.nuclide_grid[i*in.n_gridpoints], in.n_gridpoints, sizeof(NuclideGridPoint), NGP_compare);

	if( in.grid_type == NUCLIDE )
	{
		SD.length_unionized_energy_array = 0;
		SD.length_index_grid = 0;
		SD.unionized_energy_array = NULL;
		SD.index_grid = NULL;
	}

	if( in.grid_type == UNIONIZED )
	{
		if(mype == 0) printf("Intializing unionized grid...\n");

		SD.length_unionized_energy_array = in.n_isotopes * in.n_gridpoints;
		SD.unionized_energy_array = (double *) malloc( (size_t) SD.length_unionized_energy_array * sizeof(double));
		assert(SD.unionized_energy_array != NULL );
		nbytes += (size_t) SD.length_unionized_energy_array * sizeof(double);

		for( int i = 0; i < SD.length_unionized_energy_array; i++ )
			SD.unionized_energy_array[i] = SD.nuclide_grid[i].energy;

		qsort( SD.unionized_energy_array, SD.length_unionized_energy_array, sizeof(double), double_compare);

		SD.length_index_grid = (long) SD.length_unionized_energy_array * in.n_isotopes;
		SD.index_grid = (int *) malloc( (size_t) SD.length_index_grid * sizeof(int));
		assert(SD.index_grid != NULL);
		nbytes += (size_t) SD.length_index_grid * sizeof(int);

		int * idx_low = (int *) calloc( in.n_isotopes, sizeof(int));
		assert(idx_low != NULL );
		double * energy_high = (double *) malloc( in.n_isotopes * sizeof(double));
		assert(energy_high != NULL );

		for( int i = 0; i < in.n_isotopes; i++ )
			energy_high[i] = SD.nuclide_grid[i * in.n_gridpoints + 1].energy;

		for( long e = 0; e < SD.length_unionized_energy_array; e++ )
		{
			double unionized_energy = SD.unionized_energy_array[e];
			for( long i = 0; i < in.n_isotopes; i++ )
			{
				if( unionized_energy < energy_high[i] )
					SD.index_grid[e * in.n_isotopes + i] = idx_low[i];
				else if( idx_low[i] == in.n_gridpoints - 2 )
					SD.index_grid[e * in.n_isotopes + i] = idx_low[i];
				else
				{
					idx_low[i]++;
					SD.index_grid[e * in.n_isotopes + i] = idx_low[i];
					energy_high[i] = SD.nuclide_grid[i * in.n_gridpoints + idx_low[i] + 1].energy;
				}
			}
		}

		free(idx_low);
		free(energy_high);
	}

	if( in.grid_type == HASH )
	{
		if(mype == 0) printf("Intializing hash grid...\n");

		SD.length_unionized_energy_array = 0;
		SD.unionized_energy_array = NULL;
		SD.length_index_grid = (long) in.hash_bins * in.n_isotopes;
		SD.index_grid = (int *) malloc( (size_t) SD.length_index_grid * sizeof(int));
		assert(SD.index_grid != NULL);
		nbytes += (size_t) SD.length_index_grid * sizeof(int);

		double du = 1.0 / in.hash_bins;

		for( long e = 0; e < in.hash_bins; e++ )
		{
			double energy = e * du;
			for( long i = 0; i < in.n_isotopes; i++ )
			{
				SD.index_grid[e * in.n_isotopes + i] =
					grid_search_nuclide( in.n_gridpoints, energy,
						SD.nuclide_grid + i * in.n_gridpoints, 0, in.n_gridpoints-1);
			}
		}
	}

	if(mype == 0) printf("Intializing material data...\n");

	SD.num_nucs = load_num_nucs(in.n_isotopes);
	SD.length_num_nucs = 12;

	SD.mats = load_mats(SD.num_nucs, in.n_isotopes, &SD.max_num_nucs);
	SD.length_mats = SD.length_num_nucs * SD.max_num_nucs;

	SD.concs = load_concs(SD.num_nucs, SD.max_num_nucs);
	SD.length_concs = SD.length_mats;

	SD.verification = NULL;
	SD.length_verification = 0;
	SD.p_energy_samples = NULL;
	SD.length_p_energy_samples = 0;
	SD.mat_samples = NULL;
	SD.length_mat_samples = 0;

	if(mype == 0)
		printf("Intialization complete. Allocated %.0lf MB of data.\n", nbytes/1024.0/1024.0 );

	return SD;
}

SimulationData move_simulation_data_to_device( Inputs in, int mype, SimulationData SD )
{
	(void) in;
	(void) mype;

	SimulationData GSD = {};
	GSD.length_num_nucs = SD.length_num_nucs;
	GSD.length_concs = SD.length_concs;
	GSD.length_mats = SD.length_mats;
	GSD.length_unionized_energy_array = SD.length_unionized_energy_array;
	GSD.length_index_grid = SD.length_index_grid;
	GSD.length_nuclide_grid = SD.length_nuclide_grid;
	GSD.max_num_nucs = SD.max_num_nucs;
	GSD.length_verification = 0;
	GSD.length_p_energy_samples = 0;
	GSD.length_mat_samples = 0;

	if( SD.length_num_nucs > 0 )
	{
		gpuErrchk( cudaMalloc((void **) &GSD.num_nucs, (size_t) SD.length_num_nucs * sizeof(int)) );
		gpuErrchk( cudaMemcpy(GSD.num_nucs, SD.num_nucs, (size_t) SD.length_num_nucs * sizeof(int), cudaMemcpyHostToDevice) );
	}

	if( SD.length_concs > 0 )
	{
		gpuErrchk( cudaMalloc((void **) &GSD.concs, (size_t) SD.length_concs * sizeof(double)) );
		gpuErrchk( cudaMemcpy(GSD.concs, SD.concs, (size_t) SD.length_concs * sizeof(double), cudaMemcpyHostToDevice) );
	}

	if( SD.length_mats > 0 )
	{
		gpuErrchk( cudaMalloc((void **) &GSD.mats, (size_t) SD.length_mats * sizeof(int)) );
		gpuErrchk( cudaMemcpy(GSD.mats, SD.mats, (size_t) SD.length_mats * sizeof(int), cudaMemcpyHostToDevice) );
	}

	if( SD.length_unionized_energy_array > 0 )
	{
		gpuErrchk( cudaMalloc((void **) &GSD.unionized_energy_array,
			(size_t) SD.length_unionized_energy_array * sizeof(double)) );
		gpuErrchk( cudaMemcpy(GSD.unionized_energy_array, SD.unionized_energy_array,
			(size_t) SD.length_unionized_energy_array * sizeof(double), cudaMemcpyHostToDevice) );
	}

	if( SD.length_index_grid > 0 )
	{
		gpuErrchk( cudaMalloc((void **) &GSD.index_grid, (size_t) SD.length_index_grid * sizeof(int)) );
		gpuErrchk( cudaMemcpy(GSD.index_grid, SD.index_grid,
			(size_t) SD.length_index_grid * sizeof(int), cudaMemcpyHostToDevice) );
	}

	if( SD.length_nuclide_grid > 0 )
	{
		gpuErrchk( cudaMalloc((void **) &GSD.nuclide_grid,
			(size_t) SD.length_nuclide_grid * sizeof(NuclideGridPoint)) );
		gpuErrchk( cudaMemcpy(GSD.nuclide_grid, SD.nuclide_grid,
			(size_t) SD.length_nuclide_grid * sizeof(NuclideGridPoint), cudaMemcpyHostToDevice) );
	}

	GSD.verification = NULL;
	GSD.p_energy_samples = NULL;
	GSD.mat_samples = NULL;

	return GSD;
}

void release_device_memory(SimulationData GSD)
{
	if( GSD.num_nucs ) gpuErrchk( cudaFree(GSD.num_nucs) );
	if( GSD.concs ) gpuErrchk( cudaFree(GSD.concs) );
	if( GSD.mats ) gpuErrchk( cudaFree(GSD.mats) );
	if( GSD.unionized_energy_array ) gpuErrchk( cudaFree(GSD.unionized_energy_array) );
	if( GSD.index_grid ) gpuErrchk( cudaFree(GSD.index_grid) );
	if( GSD.nuclide_grid ) gpuErrchk( cudaFree(GSD.nuclide_grid) );
	if( GSD.verification ) gpuErrchk( cudaFree(GSD.verification) );
	if( GSD.p_energy_samples ) gpuErrchk( cudaFree(GSD.p_energy_samples) );
	if( GSD.mat_samples ) gpuErrchk( cudaFree(GSD.mat_samples) );
}

